    { "name": "navigate-member-form", "context": ["memberId?"] },
    { "name": "navigate-calendar", "context": [] },
    { "name": "navigate-inventory", "context": [] },
    { "name": "member-checkin", "context": ["memberId"] },
    { "name": "navigate-points-history", "context": ["memberId?"] },
    { "name": "navigate-member-bookings", "context": ["memberId"] },
    { "name": "save-member", "context": ["member"] },
    { "name": "delete-member", "context": ["memberId"] },
    { "name": "open-points-rule-sheet", "context": [] },
    { "name": "open-redeem-sheet", "context": ["memberId?"] },
    { "name": "calendar-prev", "context": [] },
    { "name": "calendar-next", "context": [] },
    { "name": "calendar-today", "context": [] },
    { "name": "navigate-course-form", "context": ["courseId?"] },
    { "name": "open-booking-sheet", "context": ["courseId"] },
    { "name": "deduct-course-materials", "context": ["courseId"] },
    { "name": "save-course", "context": ["course"] },
    { "name": "open-inventory-form", "context": ["itemId?"] },
    { "name": "navigate-inventory-log", "context": [] },
    { "name": "backup-data", "context": [] },
    { "name": "restore-data", "context": [] }
  ],
  "bindings": [
    { "path": "/summary/count", "type": "number" },
    { "path": "/today/courses", "type": "Course[]" },
    { "path": "/dormant/count", "type": "number" },
    { "path": "/members/filter", "type": "string" },
    { "path": "/members", "type": "Member[]" },
    { "path": "/member/{id}/points", "type": "number" },
    { "path": "/member/{id}/works", "type": "WorkImage[]" },
    { "path": "/member/{id}/crafts", "type": "string[]" },
    { "path": "/points/total-issued", "type": "number" },
    { "path": "/points/total-redeemed", "type": "number" },
    { "path": "/points/records", "type": "PointRecord[]" },
    { "path": "/calendar/view", "type": "'day'|'week'|'month'" },
    { "path": "/calendar/courses", "type": "Course[]" },
    { "path": "/course/{id}/students", "type": "Booking[]" },
    { "path": "/course/{id}/materials", "type": "CourseMaterial[]" },
    { "path": "/inventory", "type": "InventoryItem[]" },
    { "path": "/inventory/low-stock-count", "type": "number" },
    { "path": "/inventory-log", "type": "InventoryLog[]" },
    { "path": "/inventory-log/filter-type", "type": "'all'|'in'|'out'|'auto-deduct'" },
    { "path": "/settings/dormant-threshold", "type": "number" },
    { "path": "/settings/points-ratio", "type": "number" }
  ],
  "testTargets": [
    { "id": "tab-home", "type": "tab" },
    { "id": "tab-members", "type": "tab" },
    { "id": "tab-calendar", "type": "tab" },
    { "id": "tab-points", "type": "tab" },
    { "id": "tab-inventory", "type": "tab" },
    { "id": "members-empty-state", "type": "empty" },
    { "id": "home-today-empty", "type": "empty" },
    { "id": "home-dormant-alert-card", "type": "assertion" },
    { "id": "member-detail-points-balance", "type": "assertion" },
    { "id": "points-total-issued", "type": "assertion" },
    { "id": "points-total-redeemed", "type": "assertion" },
    { "id": "calendar-empty-state", "type": "empty" },
    { "id": "inventory-empty-state", "type": "empty" },
    { "id": "inventory-low-stock-alert", "type": "assertion" }
  ]
}

